import io
import os
import json
import time
from typing import Tuple, Optional

import torch
import torch.nn as nn
import torch.nn.functional as F
from PIL import Image
from torchvision import models
from torchvision.transforms import functional as TF

from fastapi import FastAPI, File, UploadFile, HTTPException, Request
from fastapi.responses import JSONResponse

APP_TITLE = os.getenv("APP_TITLE", "pytorch-image-classifier")
MODEL_NAME = os.getenv("MODEL_NAME", "resnet18")
MODEL_WEIGHTS = os.getenv("MODEL_WEIGHTS", "DEFAULT")  # e.g., DEFAULT
MODEL_PATH = os.getenv("MODEL_PATH", "")  # optional torchscript or state_dict
CLASS_NAMES_PATH = os.getenv("CLASS_NAMES_PATH", "")  # optional json list
DEVICE = os.getenv("DEVICE", "cuda" if torch.cuda.is_available() else "cpu")
TOPK = int(os.getenv("TOPK", "1"))

app = FastAPI(title=APP_TITLE)

_model: Optional[nn.Module] = None
_class_names: Optional[list] = None


def _load_class_names() -> Optional[list]:
    if not CLASS_NAMES_PATH:
        return None
    with open(CLASS_NAMES_PATH, "r", encoding="utf-8") as f:
        data = json.load(f)
    if isinstance(data, dict) and "classes" in data:
        data = data["classes"]
    return data if isinstance(data, list) else None


def _build_model() -> nn.Module:
    if MODEL_PATH:
        try:
            m = torch.jit.load(MODEL_PATH, map_location=DEVICE)
            m.eval()
            return m
        except Exception:
            pass

    name = MODEL_NAME.lower()
    if name == "resnet18":
        weights = getattr(models, "ResNet18_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.resnet18(weights=weights)
    elif name == "resnet50":
        weights = getattr(models, "ResNet50_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.resnet50(weights=weights)
    elif name == "mobilenet_v3_small":
        weights = getattr(models, "MobileNet_V3_Small_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.mobilenet_v3_small(weights=weights)
    elif name == "mobilenet_v3_large":
        weights = getattr(models, "MobileNet_V3_Large_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.mobilenet_v3_large(weights=weights)
    elif name == "efficientnet_b0":
        weights = getattr(models, "EfficientNet_B0_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.efficientnet_b0(weights=weights)
    else:
        weights = getattr(models, "ResNet18_Weights").DEFAULT if MODEL_WEIGHTS.upper() == "DEFAULT" else None
        m = models.resnet18(weights=weights)

    if MODEL_PATH:
        sd = torch.load(MODEL_PATH, map_location="cpu")
        if isinstance(sd, dict) and "state_dict" in sd:
            sd = sd["state_dict"]
        try:
            m.load_state_dict(sd, strict=False)
        except Exception:
            pass

    m.to(DEVICE)
    m.eval()
    return m


def _ensure_model():
    global _model, _class_names
    if _model is None:
        _model = _build_model()
    if _class_names is None:
        _class_names = _load_class_names()


def _pil_from_bytes(b: bytes) -> Image.Image:
    return Image.open(io.BytesIO(b)).convert("RGB")


def _tensor_from_pil(img: Image.Image) -> torch.Tensor:
    t = TF.to_tensor(img).unsqueeze(0)
    return t.to(DEVICE)


@torch.inference_mode()
def _predict(x: torch.Tensor) -> Tuple[int, float]:
    logits = _model(x)
    if isinstance(logits, (tuple, list)):
        logits = logits[0]
    probs = F.softmax(logits, dim=1)
    conf, idx = torch.max(probs, dim=1)
    return int(idx.item()), float(conf.item())


@app.on_event("startup")
def _startup():
    _ensure_model()


@app.get("/health")
def health():
    return {"status": "ok", "device": DEVICE, "model": MODEL_NAME}


@app.post("/predict")
async def predict(file: UploadFile = File(...), request: Request = None):
    _ensure_model()
    try:
        b = await file.read()
        img = _pil_from_bytes(b)
        x = _tensor_from_pil(img)
        idx, conf = _predict(x)
        label = _class_names[idx] if (_class_names and 0 <= idx < len(_class_names)) else str(idx)
        return JSONResponse(
            {
                "class": label,
                "confidence": conf,
            }
        )
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


